import{_ as t,a,b as d,c as i}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as o,o as r,c as s,a2 as n}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"WebDAV चैनल जोड़ना","description":"","frontmatter":{},"headers":[],"relativePath":"hi/upload/webdav.md","filePath":"hi/upload/webdav.md","lastUpdated":1781962217000}'),l={name:"hi/upload/webdav.md"};function c(p,e,h,u,b,f){return r(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="webdav-चैनल-जोड़ना" tabindex="-1">WebDAV चैनल जोड़ना <a class="header-anchor" href="#webdav-चैनल-जोड़ना" aria-label="Permalink to &quot;WebDAV चैनल जोड़ना&quot;">​</a></h1><h2 id="कब-सबसे-सही-है" tabindex="-1">कब सबसे सही है <a class="header-anchor" href="#कब-सबसे-सही-है" aria-label="Permalink to &quot;कब सबसे सही है&quot;">​</a></h2><p>WebDAV channel का उपयोग तब करें जब:</p><ul><li>आपके पास NAS, cloud drive या object storage service है जो WebDAV endpoint देती है।</li><li>आप uploaded images को अपने WebDAV directory में रखना चाहते हैं।</li><li>आप credentials को लंबे समय तक frontend में expose करने के बजाय D1 <code>upload_channels</code> table में save करना चाहते हैं।</li></ul><h2 id="शुरू-करने-से-पहले-क्या-चाहिए" tabindex="-1">शुरू करने से पहले क्या चाहिए <a class="header-anchor" href="#शुरू-करने-से-पहले-क्या-चाहिए" aria-label="Permalink to &quot;शुरू करने से पहले क्या चाहिए&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ज़रूरत</th><th>उपयोग</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>server-side WebDAV URL, जैसे <code>https://nas.example.com/dav</code>।</td></tr><tr><td>Username</td><td>WebDAV service में sign in करने के लिए।</td></tr><tr><td>Password</td><td>WebDAV service में sign in करने के लिए।</td></tr><tr><td>Authentication mode</td><td>default <code>Basic</code> है। <code>Digest</code> या auto negotiation केवल तब use करें जब server मांगे।</td></tr><tr><td>Storage directory</td><td>files store करने की directory। default <code>imgbed</code>।</td></tr></tbody></table><h2 id="कहाँ-जोड़ें" tabindex="-1">कहाँ जोड़ें <a class="header-anchor" href="#कहाँ-जोड़ें" aria-label="Permalink to &quot;कहाँ जोड़ें&quot;">​</a></h2><ol><li>System Settings खोलें।</li><li>Upload Settings पर जाएँ।</li><li>ऊपर दाएँ कोने में Add Channel पर क्लिक करें।</li><li><code>WebDAV</code> चुनें।</li></ol><h2 id="फ़ील्ड-संदर्भ" tabindex="-1">फ़ील्ड संदर्भ <a class="header-anchor" href="#फ़ील्ड-संदर्भ" aria-label="Permalink to &quot;फ़ील्ड संदर्भ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>क्या करता है</th><th>आवश्यक</th></tr></thead><tbody><tr><td>Channel name</td><td>WebDAV channel का आसान नाम, जैसे <code>koofr</code> या <code>nas</code>।</td><td>हाँ</td></tr><tr><td>Endpoint</td><td><code>https://</code> सहित पूरा WebDAV endpoint।</td><td>हाँ</td></tr><tr><td>Username</td><td>WebDAV login username।</td><td>हाँ</td></tr><tr><td>Password</td><td>WebDAV login password।</td><td>हाँ</td></tr><tr><td>Authentication mode</td><td>आम तौर पर <code>Basic</code>; server digest authentication मांगे तो <code>Digest</code> use करें।</td><td>हाँ</td></tr><tr><td>Storage directory</td><td>जहाँ files रखी जाती हैं। default <code>imgbed</code>।</td><td>नहीं</td></tr></tbody></table><h2 id="उदाहरण-fie-nl-tab-digital" tabindex="-1">उदाहरण: fie.nl.tab.digital <a class="header-anchor" href="#उदाहरण-fie-nl-tab-digital" aria-label="Permalink to &quot;उदाहरण: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-app-password-बनाएँ" tabindex="-1">1. App Password बनाएँ <a class="header-anchor" href="#_1-app-password-बनाएँ" aria-label="Permalink to &quot;1. App Password बनाएँ&quot;">​</a></h3><p>अपने account security settings खोलें, application passwords खोजें, और नया app password बनाएँ।</p><p><img src="'+t+'" alt="App password बनाएँ" loading="lazy"></p><p>बनने के बाद नया app password copy और save करें। यह आम तौर पर केवल एक बार दिखता है।</p><p><img src="'+a+'" alt="नया app password save करें" loading="lazy"></p><h3 id="_2-imgbed-में-webdav-configuration-भरें" tabindex="-1">2. ImgBed में WebDAV configuration भरें <a class="header-anchor" href="#_2-imgbed-में-webdav-configuration-भरें" aria-label="Permalink to &quot;2. ImgBed में WebDAV configuration भरें&quot;">​</a></h3><p>ImgBed पर लौटें और WebDAV channel जोड़ें:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Endpoint</td><td><code>https://fie.nl.tab.digital/</code> द्वारा दिया गया WebDAV URL।</td></tr><tr><td>Username</td><td>आपका WebDAV username।</td></tr><tr><td>Password</td><td>अभी बनाया गया app password।</td></tr><tr><td>Authentication mode</td><td>अधिकतर मामलों में <code>Basic</code> से शुरू करें।</td></tr><tr><td>Storage directory</td><td>default <code>imgbed</code>; चाहें तो custom directory use करें।</td></tr></tbody></table><p><img src="'+d+'" alt="Configuration भरें" loading="lazy"></p><h2 id="बड़ी-फ़ाइलों-का-upload-behavior" tabindex="-1">बड़ी फ़ाइलों का upload behavior <a class="header-anchor" href="#बड़ी-फ़ाइलों-का-upload-behavior" aria-label="Permalink to &quot;बड़ी फ़ाइलों का upload behavior&quot;">​</a></h2><p>WebDAV channel अब real session-based chunked upload का उपयोग करता है।</p><p>छोटी files एक complete file के रूप में upload होती हैं। 64 MiB से बड़ी files लगभग 10 MiB chunks में अपने आप split होकर remote chunk directory में upload होती हैं।</p><p>WebDAV service को <code>partial update</code> या offset-based writes support करने की ज़रूरत नहीं है। ImgBed remote server पर chunks को एक बड़ी file में merge नहीं करता। इसके बजाय chunk manifest store करता है और file request होने पर chunks को क्रम से पढ़ता है।</p><p>व्यवहार में:</p><table tabindex="0"><thead><tr><th>File Size</th><th>Upload Method</th><th>Remote Storage Layout</th></tr></thead><tbody><tr><td>64 MiB या कम</td><td>Normal upload</td><td>एक complete file</td></tr><tr><td>64 MiB से अधिक</td><td>Real session chunked upload</td><td>कई chunk files वाली chunk directory</td></tr></tbody></table><p>chunk directory केवल remote storage layout को प्रभावित करती है। ImgBed में file URL नहीं बदलता। उपयोगकर्ता file को वही original <code>/file/...</code> link से access करते हैं।</p><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Upload Settings खोलें।</li><li>Add Channel पर क्लिक करें।</li><li><code>WebDAV</code> चुनें।</li><li>पहचानने लायक channel name डालें, जैसे <code>koofr</code>।</li><li>WebDAV endpoint डालें, जैसे <code>https://app.koofr.net/dav/Koofr</code>।</li><li>username और password डालें।</li><li>authentication mode default रूप से <code>Basic</code> रखें।</li><li>storage directory को <code>imgbed</code> रखें, या अपनी directory डालें।</li><li>Save पर क्लिक करें।</li><li>save के बाद channel card जाँचें, उपलब्ध हो तो capacity query करें, और test file upload करें।</li></ol><h2 id="कैसे-जाँचें" tabindex="-1">कैसे जाँचें <a class="header-anchor" href="#कैसे-जाँचें" aria-label="Permalink to &quot;कैसे जाँचें&quot;">​</a></h2><table tabindex="0"><thead><tr><th>जाँच</th><th>कैसे verify करें</th></tr></thead><tbody><tr><td>Channel card दिखता है</td><td>save करने के बाद Upload Settings page में WebDAV channel card दिखना चाहिए।</td></tr><tr><td>Channel enabled है</td><td>card के ऊपर दाएँ switch को on रहना चाहिए।</td></tr><tr><td>Credentials save हैं</td><td>detail view में Endpoint, username, authentication mode और storage directory दिखने चाहिए।</td></tr><tr><td>छोटी file upload होती है</td><td>test image upload करें और file WebDAV directory में दिखाई दे।</td></tr><tr><td>बड़ी file rule काम करता है</td><td>64 MiB से बड़ी files chunked upload use करती हैं और remote chunk directory बनाती हैं।</td></tr><tr><td>Capacity query काम करती है</td><td>server capacity info support करता हो तो query used और total capacity दिखाएगी।</td></tr></tbody></table><p><img src="'+i+`" alt="Quota query successful" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="बड़ी-webdav-files-chunk-directory-क्यों-बनाती-हैं" tabindex="-1">बड़ी WebDAV files chunk directory क्यों बनाती हैं? <a class="header-anchor" href="#बड़ी-webdav-files-chunk-directory-क्यों-बनाती-हैं" aria-label="Permalink to &quot;बड़ी WebDAV files chunk directory क्यों बनाती हैं?&quot;">​</a></h3><p>यह बड़ी files के लिए वर्तमान storage method है।</p><p>64 MiB से बड़ी files एक बड़ी remote file में merge नहीं होतीं। वे chunk directory के रूप में रखी जाती हैं। ImgBed chunk manifest record करता है और chunks को क्रम से पढ़कर पूरा content लौटाता है।</p><h3 id="बड़ी-file-upload-fail-हो-तो-पहले-क्या-जाँचें" tabindex="-1">बड़ी file upload fail हो तो पहले क्या जाँचें? <a class="header-anchor" href="#बड़ी-file-upload-fail-हो-तो-पहले-क्या-जाँचें" aria-label="Permalink to &quot;बड़ी file upload fail हो तो पहले क्या जाँचें?&quot;">​</a></h3><p>पहले Endpoint, username, password और storage directory जाँचें। फिर confirm करें कि WebDAV service directory creation, file writing और file reading allow करती है।</p><p>अगर capacity query fail हो लेकिन छोटी file upload काम करे, तो server शायद capacity reporting support नहीं करता या restrict करता है। इसका मतलब upload unavailable होना ज़रूरी नहीं।</p><h3 id="कौन-सा-authentication-mode-इस्तेमाल-करें" tabindex="-1">कौन सा authentication mode इस्तेमाल करें? <a class="header-anchor" href="#कौन-सा-authentication-mode-इस्तेमाल-करें" aria-label="Permalink to &quot;कौन सा authentication mode इस्तेमाल करें?&quot;">​</a></h3><p><code>Basic</code> से शुरू करें।</p><p>server स्पष्ट रूप से digest authentication मांगे तो <code>Digest</code> use करें।</p><p>अगर unsure हों, automatic negotiation use करें।</p><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebDAV endpoint, username और password तैयार करें</span></span>
<span class="line"><span>-&gt; Upload Settings खोलें</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; WebDAV चुनें</span></span>
<span class="line"><span>-&gt; Endpoint / username / password डालें</span></span>
<span class="line"><span>-&gt; authentication mode को default Basic रखें</span></span>
<span class="line"><span>-&gt; storage directory को default imgbed रखें</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; capacity query करें</span></span>
<span class="line"><span>-&gt; test file upload करें</span></span></code></pre></div>`,45)])])}const k=o(l,[["render",c]]);export{y as __pageData,k as default};
